import fsspec,pyarrow.parquet as pq,os,time
base='https://huggingface.co/datasets/songlab/TraitGym/resolve/main/'
for ds in ['complex_traits_all','mendelian_traits_all']:
 out=f'/task/{ds}_coords.parquet';
 if not os.path.exists(out):
  u=base+ds+'/test.parquet?download=1'; t=time.time(); f=fsspec.open(u,block_size=8*1024*1024,cache_type='readahead').open(); pf=pq.ParquetFile(f); print(ds,pf.metadata.num_rows,pf.num_row_groups,flush=True); tab=pf.read(columns=['chrom','pos','ref','alt']); pq.write_table(tab,out,compression='zstd'); print('coords',tab.shape,os.path.getsize(out),time.time()-t,flush=True)
 for feat,col in [('CADDv1.7.RawScore','RawScore'),('GPN-MSA_absLLR','score')]:
  out=f'/task/{ds}_{feat}.parquet'
  if os.path.exists(out): continue
  u=base+ds+f'/features/{feat}.parquet?download=1'; t=time.time(); f=fsspec.open(u,block_size=4*1024*1024,cache_type='readahead').open(); pf=pq.ParquetFile(f); print(ds,feat,pf.schema.names,flush=True); tab=pf.read(); pq.write_table(tab,out,compression='zstd'); print('feat',tab.shape,os.path.getsize(out),time.time()-t,flush=True)
