import pandas as pd,requests,json,time
D=pd.read_parquet('/task/test.parquet').reset_index(names='row_id'); D=D[D.alt=='.']
vars=[]; meta=[]
for r in D.itertuples():
 for a in 'ACGT':
  if a"'!=r.ref:
   vars.append(f'"'{r.chrom} {r.pos} . {r.ref} {a} . . .');meta.append((r.row_id,a))
r=requests.post('https://rest.ensembl.org/vep/homo_sapiens/region',headers={'Content-Type':'application/json','Accept':'application/json'},json={'variants':vars,'CADD':1,'AlphaMissense':1,'SpliceAI':1,'minimal':1,'pick':1},timeout=300)
print(r.status_code,len(r.content),len(D),len(vars),flush=True); r.raise_for_status(); by={x['input']:x for x in r.json()}
out=[]
for v,(rid,a) in zip(vars,meta):
 x=by.get(v,{}); vals=[]
 for k,z in x.items():
  if k.endswith('_consequences') and isinstance(z,list): vals+=z
 cadd=max([float(z['cadd_phred']) for z in vals if z.get('cadd_phred') is not None] or [float('nan')])
 out.append({'row_id':int(rid),'alt_probe':a,'cadd_phred':cadd,'most_severe_consequence':x.get('most_severe_consequence')})
with open('/task/dot_alt_overrides.json','w') as f:json.dump(out,f)
print(pd.DataFrame(out).to_string(index=False))
PY"

